const createShipmentsForOrderSellers = `-- name: CreateShipmentsForOrderSellers :many
INSERT INTO shipments (order_id, seller_id)
SELECT DISTINCT oi.order_id, oi.seller_id
FROM order_items oi
WHERE oi.order_id = $1
RETURNING id, order_id, seller_id, provider_id, tracking_number, label_url, provider_metadata, status, shipped_at, delivered_at, created_at, updated_at
`

func (q *Queries) CreateShipmentsForOrderSellers(ctx context.Context, orderID pgtype.UUID) ([]Shipment, error) {
	rows, err := q.db.Query(ctx, createShipmentsForOrderSellers, orderID)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	var items []Shipment
	for rows.Next() {
		var i Shipment
		if err := rows.Scan(
			&i.ID,
			&i.OrderID,
			&i.SellerID,
			&i.ProviderID,
			&i.TrackingNumber,
			&i.LabelUrl,
			&i.ProviderMetadata,
			&i.Status,
			&i.ShippedAt,
			&i.DeliveredAt,
			&i.CreatedAt,
			&i.UpdatedAt,
		); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

