const upsertCartItem = `-- name: UpsertCartItem :one
INSERT INTO cart_items (cart_id, product_id, variant_id, quantity, selected)
VALUES ($1, $2, $3, $4, TRUE)
ON CONFLICT (cart_id, variant_id) DO UPDATE
SET quantity = cart_items.quantity + EXCLUDED.quantity,
    selected = TRUE
RETURNING id, cart_id, product_id, variant_id, quantity, created_at, updated_at, selected
`

type UpsertCartItemParams struct {
	CartID    pgtype.UUID `db:"cart_id" json:"cart_id"`
	ProductID pgtype.UUID `db:"product_id" json:"product_id"`
	VariantID pgtype.UUID `db:"variant_id" json:"variant_id"`
	Quantity  int32       `db:"quantity" json:"quantity"`
}

func (q *Queries) UpsertCartItem(ctx context.Context, arg UpsertCartItemParams) (CartItem, error) {
	row := q.db.QueryRow(ctx, upsertCartItem,
		arg.CartID,
		arg.ProductID,
		arg.VariantID,
		arg.Quantity,
	)
	var i CartItem
	err := row.Scan(
		&i.ID,
		&i.CartID,
		&i.ProductID,
		&i.VariantID,
		&i.Quantity,
		&i.CreatedAt,
		&i.UpdatedAt,
		&i.Selected,
	)
	return i, err
}
